 1→import { useQuery, useInfiniteQuery } from '@tanstack/react-query';
 2→import { getMyStories, getMyLibrary, getStoryById, getChapter, getChapterComments, getChapterCommentCounts, getUserStories } from '../../../../API/StoryApi';
 3→
 4→export const useMyStories = (token) => {
 5→    return useQuery({
 6→        queryKey: ['myStories'],
 7→        queryFn: () => getMyStories(token),
 8→        enabled: !!token,
 9→        staleTime: 30000,
10→        refetchOnWindowFocus: false,
11→    });
12→};
13→
14→export const useMyLibrary = (token) => {
15→    return useQuery({
16→        queryKey: ['myLibrary'],
17→        queryFn: () => getMyLibrary(token),
18→        enabled: !!token,
19→        staleTime: 30000,
20→        refetchOnWindowFocus: false,
21→    });
22→};
23→
24→export const useStoryDetail = (storyId, token) => {
25→    return useQuery({
26→        queryKey: ['story', storyId],
27→        queryFn: () => getStoryById(storyId, token),
28→        enabled: !!storyId,
29→        staleTime: 30000,
30→        refetchOnWindowFocus: false,
31→    });
32→};
33→
34→export const useChapter = (storyId, chapterId, token) => {
35→    return useQuery({
36→        queryKey: ['chapter', storyId, chapterId],
37→        queryFn: () => getChapter(storyId, chapterId, token),
38→        enabled: !!storyId && !!chapterId,
39→        staleTime: 60000,
40→        refetchOnWindowFocus: false,
41→    });
42→};
43→
44→export const useChapterCommentCounts = (chapterId, token) => {
45→    return useQuery({
46→        queryKey: ['chapterCommentCounts', chapterId],
47→        queryFn: () => getChapterCommentCounts(chapterId, token),
48→        enabled: !!chapterId,
49→        staleTime: 30000,
50→        refetchOnWindowFocus: false,
51→    });
52→};
53→
54→export const useUserStories = (userId, token) => {
55→    return useInfiniteQuery({
56→        queryKey: ['userStories', userId],
57→        queryFn: ({ pageParam }) => getUserStories(userId, token, 5, pageParam),
58→        initialPageParam: undefined,
59→        getNextPageParam: (lastPage) => {
60→            if (lastPage.hasMore) {
61→                const lastStory = lastPage.data[lastPage.data.length - 1];
62→                return new Date(lastStory.created_at).toISOString();
63→            }
64→            return undefined;
65→        },
66→        enabled: !!userId,
67→        staleTime: 30000,
68→        refetchOnWindowFocus: false,
69→    });
70→};
71→
72→export const useChapterComments = (chapterId, paragraphIndex, token) => {
73→    return useQuery({
74→        queryKey: ['chapterComments', chapterId, paragraphIndex],
75→        queryFn: () => getChapterComments(chapterId, paragraphIndex, token),
76→        enabled: !!chapterId && paragraphIndex !== null && paragraphIndex !== undefined,
77→        staleTime: 30000,
78→        refetchOnWindowFocus: false,
79→    });
80→};
