  1→import { useMutation, useQueryClient } from '@tanstack/react-query';
  2→import {
  3→    createStory,
  4→    updateStory,
  5→    deleteStory,
  6→    createChapter,
  7→    updateChapter,
  8→    deleteChapter,
  9→    reorderChapters,
 10→    toggleStoryVote,
 11→    toggleStoryLibrary,
 12→    addChapterComment,
 13→} from '../../../../API/StoryApi';
 14→
 15→export const useCreateStory = (token) => {
 16→    const queryClient = useQueryClient();
 17→    return useMutation({
 18→        mutationFn: (formData) => createStory(token, formData),
 19→        onSuccess: () => {
 20→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 21→        },
 22→    });
 23→};
 24→
 25→export const useUpdateStory = (token) => {
 26→    const queryClient = useQueryClient();
 27→    return useMutation({
 28→        mutationFn: ({ storyId, formData }) => updateStory(token, storyId, formData),
 29→        onSuccess: (_data, { storyId }) => {
 30→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 31→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 32→        },
 33→    });
 34→};
 35→
 36→export const useDeleteStory = (token) => {
 37→    const queryClient = useQueryClient();
 38→    return useMutation({
 39→        mutationFn: (storyId) => deleteStory(token, storyId),
 40→        onSuccess: () => {
 41→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 42→        },
 43→    });
 44→};
 45→
 46→export const useCreateChapter = (token) => {
 47→    const queryClient = useQueryClient();
 48→    return useMutation({
 49→        mutationFn: ({ storyId, title }) => createChapter(token, storyId, title),
 50→        onSuccess: (_data, { storyId }) => {
 51→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 52→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 53→        },
 54→    });
 55→};
 56→
 57→export const useUpdateChapter = (token) => {
 58→    const queryClient = useQueryClient();
 59→    return useMutation({
 60→        mutationFn: ({ storyId, chapterId, data }) => updateChapter(token, storyId, chapterId, data),
 61→        onSuccess: (_data, { storyId, chapterId }) => {
 62→            queryClient.invalidateQueries({ queryKey: ['chapter', storyId, chapterId] });
 63→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 64→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 65→        },
 66→    });
 67→};
 68→
 69→export const useDeleteChapter = (token) => {
 70→    const queryClient = useQueryClient();
 71→    return useMutation({
 72→        mutationFn: ({ storyId, chapterId }) => deleteChapter(token, storyId, chapterId),
 73→        onSuccess: (_data, { storyId }) => {
 74→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 75→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 76→        },
 77→    });
 78→};
 79→
 80→export const useReorderChapters = (token) => {
 81→    const queryClient = useQueryClient();
 82→    return useMutation({
 83→        mutationFn: ({ storyId, chapterOrder }) => reorderChapters(token, storyId, chapterOrder),
 84→        onSuccess: (_data, { storyId }) => {
 85→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 86→        },
 87→    });
 88→};
 89→
 90→export const useToggleVote = (token) => {
 91→    const queryClient = useQueryClient();
 92→    return useMutation({
 93→        mutationFn: (storyId) => toggleStoryVote(token, storyId),
 94→        onMutate: async (storyId) => {
 95→            await queryClient.cancelQueries({ queryKey: ['story', storyId] });
 96→            const previous = queryClient.getQueryData(['story', storyId]);
 97→            if (previous) {
 98→                queryClient.setQueryData(['story', storyId], (old) => ({
 99→                    ...old,
100→                    has_voted: !old.has_voted,
101→                    vote_count: old.has_voted ? (old.vote_count || 1) - 1 : (old.vote_count || 0) + 1,
102→                }));
103→            }
104→            return { previous };
105→        },
106→        onError: (_err, storyId, context) => {
107→            if (context?.previous) {
108→                queryClient.setQueryData(['story', storyId], context.previous);
109→            }
110→        },
111→        onSettled: (_data, _err, storyId) => {
112→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
113→        },
114→    });
115→};
116→
117→export const useAddChapterComment = (token) => {
118→    const queryClient = useQueryClient();
119→    return useMutation({
120→        mutationFn: ({ chapterId, data }) => addChapterComment(token, chapterId, data),
121→        onSuccess: (_data, { chapterId }) => {
122→            queryClient.invalidateQueries({ queryKey: ['chapterComments', chapterId] });
123→            queryClient.invalidateQueries({ queryKey: ['chapterCommentCounts', chapterId] });
124→        },
125→    });
126→};
127→
128→export const useToggleLibrary = (token) => {
129→    const queryClient = useQueryClient();
130→    return useMutation({
131→        mutationFn: (storyId) => toggleStoryLibrary(token, storyId),
132→        onMutate: async (storyId) => {
133→            await queryClient.cancelQueries({ queryKey: ['story', storyId] });
134→            const previous = queryClient.getQueryData(['story', storyId]);
135→            if (previous) {
136→                queryClient.setQueryData(['story', storyId], (old) => ({
137→                    ...old,
138→                    in_library: !old.in_library,
139→                }));
140→            }
141→            return { previous };
142→        },
143→        onError: (_err, storyId, context) => {
144→            if (context?.previous) {
145→                queryClient.setQueryData(['story', storyId], context.previous);
146→            }
147→        },
148→        onSettled: (_data, _err, storyId) => {
149→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
150→            queryClient.invalidateQueries({ queryKey: ['myLibrary'] });
151→        },
152→    });
153→};
154→

  1→import React from 'react';
  2→import { useNavigate } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useMyStories } from '../hooks/useStoryData';
  5→import { useDeleteStory } from '../hooks/useStoryMutations';
  6→import { motion, AnimatePresence } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import './StoryDashboard.css';
  9→
 10→const STATUS_LABELS = {
 11→    ongoing: 'Ongoing',
 12→    completed: 'Completed',
 13→    hiatus: 'Hiatus',
 14→};
 15→
 16→const StoryDashboard = () => {
 17→    const { session } = useAuth();
 18→    const token = session?.access_token;
 19→    const navigate = useNavigate();
 20→
 21→    const { data: stories, isLoading } = useMyStories(token);
 22→    const deleteMutation = useDeleteStory(token);
 23→
 24→    const handleDelete = (e, storyId, title) => {
 25→        e.stopPropagation();
 26→        if (window.confirm(`Delete "${title}"? This cannot be undone.`)) {
 27→            deleteMutation.mutate(storyId);
 28→        }
 29→    };
 30→
 31→    const getTotalWords = (chapters) => {
 32→        if (!chapters) return 0;
 33→        return chapters.reduce((sum, ch) => sum + (ch.word_count || 0), 0);
 34→    };
 35→
 36→    const getPublishedCount = (chapters) => {
 37→        if (!chapters) return 0;
 38→        return chapters.filter(ch => ch.status === 'published').length;
 39→    };
 40→
 41→    if (isLoading) {
 42→        return (
 43→            <div className="story-dashboard">
 44→                <div className="story-dashboard-loading">
 45→                    <BeatLoader size={10} color="var(--text-muted)" />
 46→                </div>
 47→            </div>
 48→        );
 49→    }
 50→
 51→    return (
 52→        <div className="story-dashboard">
 53→            <div className="story-dashboard-header">
 54→                <button className="story-dashboard-back" onClick={() => navigate(-1)}>
 55→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
 56→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
 57→                    </svg>
 58→                </button>
 59→                <h2 className="story-dashboard-title">My Stories</h2>
 60→                <button
 61→                    className="story-dashboard-new-btn"
 62→                    onClick={() => navigate('/home/stories/new')}
 63→                >
 64→                    + New Story
 65→                </button>
 66→            </div>
 67→
 68→            {(!stories || stories.length === 0) ? (
 69→                <div className="story-dashboard-empty">
 70→                    <p>You haven't written any stories yet.</p>
 71→                    <button
 72→                        className="story-dashboard-new-btn"
 73→                        onClick={() => navigate('/home/stories/new')}
 74→                    >
 75→                        Write Your First Story
 76→                    </button>
 77→                </div>
 78→            ) : (
 79→                <div className="story-dashboard-list">
 80→                    <AnimatePresence>
 81→                        {stories.map((story) => (
 82→                            <motion.div
 83→                                key={story.id}
 84→                                className="story-dashboard-card"
 85→                                initial={{ opacity: 0, y: 10 }}
 86→                                animate={{ opacity: 1, y: 0 }}
 87→                                exit={{ opacity: 0, y: -10 }}
 88→                                onClick={() => navigate(`/home/stories/${story.id}/manage`)}
 89→                            >
 90→                                <div className="story-dashboard-card-cover">
 91→                                    {story.cover_url ? (
 92→                                        <img src={story.cover_url} alt={story.title} loading="lazy" />
 93→                                    ) : (
 94→                                        <div className="story-dashboard-card-cover-placeholder">
 95→                                            <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="var(--text-muted)">
 96→                                                <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
 97→                                            </svg>
 98→                                        </div>
 99→                                    )}
100→                                </div>
101→                                <div className="story-dashboard-card-info">
102→                                    <h3 className="story-dashboard-card-title">{story.title}</h3>
103→                                    <div className="story-dashboard-card-meta">
104→                                        <span className={`story-status-badge story-status-${story.status}`}>
105→                                            {STATUS_LABELS[story.status] || story.status}
106→                                        </span>
107→                                        <span className="story-meta-dot">&middot;</span>
108→                                        <span>{getPublishedCount(story.chapters)}/{(story.chapters || []).length} chapters</span>
109→                                        <span className="story-meta-dot">&middot;</span>
110→                                        <span>{getTotalWords(story.chapters).toLocaleString()} words</span>
111→                                    </div>
112→                                    <div className="story-dashboard-card-stats">
113→                                        <span>{story.read_count || 0} reads</span>
114→                                        <span>{story.vote_count || 0} votes</span>
115→                                    </div>
116→                                </div>
117→                                <div className="story-dashboard-card-actions">
118→                                    <button
119→                                        className="story-action-btn"
120→                                        onClick={(e) => {
121→                                            e.stopPropagation();
122→                                            navigate(`/home/stories/${story.id}/edit`);
123→                                        }}
124→                                        title="Edit story details"
125→                                    >
126→                                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="var(--text-secondary)">
127→                                            <path d="M3 17.25V21h3.75L17.81 9.94l-3.75-3.75L3 17.25zM20.71 7.04c.39-.39.39-1.02 0-1.41l-2.34-2.34c-.39-.39-1.02-.39-1.41 0l-1.83 1.83 3.75 3.75 1.83-1.83z"/>
128→                                        </svg>
129→                                    </button>
130→                                    <button
131→                                        className="story-action-btn story-action-btn-danger"
132→                                        onClick={(e) => handleDelete(e, story.id, story.title)}
133→                                        title="Delete story"
134→                                    >
135→                                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
136→                                            <path d="M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z"/>
137→                                        </svg>
138→                                    </button>
139→                                </div>
140→                            </motion.div>
141→                        ))}
142→                    </AnimatePresence>
143→                </div>
144→            )}
145→        </div>
146→    );
147→};
148→
149→export default StoryDashboard;
